from flask import Flask, request, jsonify
import os
import json
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def get_cache_key():
    return f"{request.url}_cache.json"

def read_from_cache(cache_file):
    with open(cache_file, 'r') as file:
        data = json.load(file)
    if time.time() - data['timestamp'] < 3600:  # Cache expires after 1 hour
        return data['response']
    else:
        os.remove(cache_file)  # Remove expired cache
        return None

def write_to_cache(cache_file, response):
    data = {
        'response': response,
        'timestamp': time.time()
    }
    with open(cache_file, 'w') as file:
        json.dump(data, file)

